import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/introduction.md","filePath":"en/guide/introduction.md"}'),i={name:"en/guide/introduction.md"};function n(s,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-clearance" tabindex="-1">What is Clearance? <a class="header-anchor" href="#what-is-clearance" aria-label="Permalink to &quot;What is Clearance?&quot;">​</a></h2><p>Clearance is a drop-in admin panel for Laravel applications built on top of <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. It adds a Livewire 4 + Flux UI panel for managing permissions, roles, guards and settings, plus a contextual authorization layer and role ceilings - installable with one artisan command, without altering any Spatie table.</p><p>Clearance gives you:</p><ul><li><strong>Admin panel</strong> for Permissions, Roles, Guards, Settings and a Dashboard - use the pre-built routes or embed each Livewire component individually.</li><li><strong>Contextual authorization</strong> - grant a role or permission scoped to a specific model instance (a Store, a Tenant, a Project), with <code>$user-&gt;canIn()</code>, <code>@canin</code>/<code>@hasrolein</code> Blade directives, and a <code>ContextService</code> for use outside the User model.</li><li><strong>Ceiling roles</strong> - a role can declare a parent role whose permission set acts as an upper bound; a child role can never exceed its parent, enforced automatically on every save.</li><li><strong>Fine-grained write permissions</strong> - one delegable <code>clearance-{section}-write</code> permission per panel section, so you can hand out &quot;manage roles&quot; without also handing out &quot;manage settings.&quot;</li><li><strong>Super Admin</strong> with an opt-in global Gate bypass, alias detection for existing admin-like roles, and safe non-destructive promotion.</li><li><strong>Users module</strong> (opt-in) - assign roles globally or to a specific context, plus per-context permission overrides, from a per-user panel.</li><li><strong>Settings panel</strong> - per-role/guard display name, description, sanitized SVG icon and color; a configurable default role with auto-assign and bulk-assign.</li><li><strong>Guards management</strong> - database-backed guards, injected into <code>auth.guards</code> at boot, restricted to an allow-listed set of drivers.</li><li><strong>9 bundled languages</strong> (ar, en, es, fr, hi, it, pt, ru, zh), key-parity tested.</li><li><strong>Extensibility hooks</strong> - <code>HasClearance</code> trait, <code>HasPermissionGroups</code> trait, <code>ClearanceContextable</code> contract, reusable Blade components.</li><li><strong>SVG sanitization</strong> - every user-supplied icon passes through an allow-list sanitizer before storage and at render time.</li><li><strong>Security-hardened</strong> - privilege-escalation ceilings on every permission-granting path, deny-authoritative context overrides, protected <code>clearance-*</code> namespace. See <a href="/clearance-docs/en/guide/security.html">Security</a>.</li></ul><h2 id="relationship-to-spatie-laravel-permission" tabindex="-1">Relationship to spatie/laravel-permission <a class="header-anchor" href="#relationship-to-spatie-laravel-permission" aria-label="Permalink to &quot;Relationship to spatie/laravel-permission&quot;">​</a></h2><p>Clearance is not a replacement for Spatie&#39;s permission package - it&#39;s a UI and authorization layer on top of it. Roles and permissions are still Spatie&#39;s <code>Role</code> and <code>Permission</code> models, still stored in Spatie&#39;s <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> and <code>role_has_permissions</code> tables. Clearance never alters those tables. Everything Clearance adds - display metadata, role scope, ceilings, contextual assignments, per-context overrides - lives in its own set of <code>clr_*</code> tables. See <a href="/clearance-docs/en/guide/architecture.html">Architecture</a> for the full breakdown.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Version</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="key-concepts" tabindex="-1">Key concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key concepts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Summary</th></tr></thead><tbody><tr><td>Permission</td><td>A Spatie permission following the <code>group-action</code> naming convention (e.g. <code>orders-create</code>). Grants an ability.</td></tr><tr><td>Role scope</td><td>Every role is <code>global</code> (assigned directly, applies everywhere) or <code>contextual</code> (bound to specific model types, assignable only within a context instance).</td></tr><tr><td>Ceiling role</td><td>A role can declare a parent role whose permission set is an upper bound - the child can never exceed it.</td></tr><tr><td>Context</td><td>A model instance (a Store, a Tenant, a Project) that a role or permission override can be scoped to.</td></tr><tr><td>Override</td><td>A per-user, per-context <code>forced_on</code>/<code>forced_off</code> permission grant or denial - a deny always wins.</td></tr></tbody></table><p>Each of these gets a full page: <a href="/clearance-docs/en/features/permissions.html">Permissions</a>, <a href="/clearance-docs/en/features/roles.html">Roles</a>, <a href="/clearance-docs/en/features/contextual-authorization.html">Contextual Authorization</a>, <a href="/clearance-docs/en/features/users.html">Users</a>, <a href="/clearance-docs/en/features/super-admin.html">Super Admin</a>.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Ready to install Clearance? Continue to the <a href="/clearance-docs/en/guide/installation.html">Installation guide</a>.</p>',14)])])}const m=t(i,[["render",n]]);export{h as __pageData,m as default};
